SELECT TO_CHAR(REVISN_DT, 'YYYY-MM-DD HH24:MI:SS') AS REVISN_DT, REGEXP_REPLACE(DATA_SAVE_DT, '(.{4})(.{2})(.{2})(.{2})(.{2})(.{2})', '\1-\2-\3\ \4:\5:\6') AS DATA_SAVE_DT, TAGSN, #{tag_nm} AS TAG_NM, LAST_VALUE, OLD_VALUE, REVISN_RESN, REVISN_REMARK FROM RDIREVISNLOG_TB L WHERE TAGSN = ( SELECT TAGSN FROM RDITAG_TB WHERE TAG_NM = #{tag_nm} )
AND REVISN_REMARK = #{dest}
AND REPLACE(REPLACE(REPLACE(#{from_dt}, '-', ''), ' ', ''), ':', '') <= DATA_SAVE_DT AND DATA_SAVE_DT <= REPLACE(REPLACE(REPLACE(#{to_dt}, '-', ''), ' ', ''), ':', '') ORDER BY DATA_SAVE_DT DESC, REVISN_DT
